Description:
Add fastify app plugin

```
fastify.addHook("preHandler", app.authenticate);
```

```
import { FastifyPluginAsync, FastifyRequest, FastifyReply } from "fastify";
import { fromNodeHeaders } from "better-auth/node";
import fp from "fastify-plugin";

import { auth, Session, User } from "@uirules/auth";

// Extend Fastify types for custom decorations
declare module "fastify" {
  interface FastifyInstance {
    authenticate: (
      request: FastifyRequest,
      reply: FastifyReply
    ) => Promise<void>;
  }

  interface FastifyRequest {
    session?: Session;
    user?: User;
  }
}

const authPlugin: FastifyPluginAsync = fp(async (fastify) => {
  fastify.decorate(
    "authenticate",
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const authHeader = request.headers.authorization;

        if (!authHeader || !authHeader.startsWith("Bearer ")) {
          return reply.code(401).send({ error: "Unauthorized" });
        }

        // Verify token using Better Auth
        const sessionData = await auth.api.getSession({
          headers: fromNodeHeaders(request.headers),
        });

        if (!sessionData) {
          return reply.code(401).send({ error: "Invalid or expired token" });
        }

        // Attach session details to the request for later use
        request.session = sessionData.session;
        request.user = sessionData.user;
      } catch (err) {
        return reply.code(500).send({ error: "Authentication error" });
      }
    }
  );
});

export default fp(authPlugin);
```
